import { useEffect, useState } from "react";

const AdminUsers = () => {
  const [users, setUsers] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/api/admin/users", {
      credentials: "include",
    })
      .then(res => res.json())
      .then(setUsers);
  }, []);

  return (
    <div>
      <h2>Users</h2>
      {users.map(u => (
        <p key={u.id}>{u.full_name} - {u.email}</p>
      ))}
    </div>
  );
};

export default AdminUsers;
